    "id": 27,
    "slug": "nasa-to-host-media-call-with-artemis-ii-crew-on-way-home-from-moon",
    "cat": "Ciências da Terra",
    "catCls": "terra",
    "img": "https://www.nasa.gov/wp-content/uploads/2026/04/artemis-ii-cnew-conference-advisory-april-7.jpg",
    "inline_images": [],
    "video": null,
